#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            int S, J; scanf("%d %d", &S, &J);
            if (J - S > 5) cnt++;
        }
        printf("%d\n", cnt);
    }
    return 0;
}

