import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        cnt = 0
        for _ in range(N):
            S = int(next(it))
            J = int(next(it))
            if J - S > 5:
                cnt += 1
        out_lines.append(str(cnt))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

